package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.io.File

@Singleton
class FileManagerController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  def serveFile(filename: String) = Action {
    val file = new File(s"uploads/$filename")
    if (file.exists && file.isFile) {
      Ok.sendFile(file, inline = true)
    } else {
      NotFound
    }
  }

}